// e2e/pages/LoginPage.ts
export class LoginPage {
  readonly emailInput: Locator;
  readonly passwordInput: Locator;
  readonly submitButton: Locator;

  constructor(private page: Page) {
    this.emailInput = page.getByTestId('login-email');
    this.passwordInput = page.getByTestId('login-password');
    this.submitButton = page.getByTestId('login-submit');
  }

  async goto() {
    await this.page.goto('/login');
    await expect(this.emailInput).toBeVisible();
  }

  async login(email: string, password: string) {
    await this.emailInput.fill(email);
    await this.passwordInput.fill(password);
    await this.submitButton.click();
  }

  async expectLoggedIn() {
    await expect(this.page).toHaveURL('/dashboard');
  }
}

// e2e/fixtures.ts
export const test = base.extend<{
  loginPage: LoginPage;
  testUser: { email: string; password: string; id: string };
  authenticatedPage: Page;
}>({
  testUser: async ({ request }, use) => {
    const user = await createTestUser(request);
    await use(user);
    await cleanupTestData(request);
  },
  authenticatedPage: async ({ page, testUser }, use) => {
    const loginPage = new LoginPage(page);
    await loginPage.goto();
    await loginPage.login(testUser.email, testUser.password);
    await expect(page).toHaveURL('/dashboard');
    await use(page);
  },
});

// e2e/helpers/testData.ts
export async function createTestUser(
  api: APIRequestContext,
  overrides: Partial<TestUser> = {}
): Promise<TestUser> {
  const userData = {
    email: `e2e-${Date.now()}-${Math.random().toString(36).slice(2)}@test.com`,
    password: 'TestPassword123!',
    name: 'E2E Test User',
    ...overrides,
  };
  const response = await api.post('/api/test/users', { data: userData });
  const user = await response.json();
  return { ...user, password: userData.password };
}

// Mock Stripe in test
await page.route('https://api.stripe.com/**', async (route) => {
  await route.fulfill({
    status: 200,
    contentType: 'application/json',
    body: JSON.stringify({ id: 'pi_test', status: 'succeeded' }),
  });
